      solutionCode: 'function simpleHash(str) {\n  let hash = 0;\n  for (let i = 0; i < str.length; i++) {\n    const ch = str.charCodeAt(i);\n    hash = ((hash << 5) - hash) + ch;\n    hash = hash & hash;\n  }\n  return Math.abs(hash).toString(16).padStart(8, "0");\n}\n\nfunction generateSalt() {\n  return Math.random().toString(36).slice(2, 18);\n}\n\nfunction hashPassword(password) {\n  const salt = generateSalt();\n  const hash = simpleHash(salt + password);\n  return { hash, salt };\n}\n\nfunction verifyPassword(password, storedHash, salt) {\n  const hash = simpleHash(salt + password);\n  return hash === storedHash;\n}\n\nconst { hash, salt } = hashPassword("MyPassword123");\nconsole.log("Hash:", hash);\nconsole.log("Salt:", salt);\nconsole.log("Verify correct:", verifyPassword("MyPassword123", hash, salt));\nconsole.log("Verify wrong:", verifyPassword("WrongPassword", hash, salt));',
