      description: 'JWTは認証トークンとして広く使われますが、不適切な実装は重大な脆弱性を招きます。',
      task: 'JWTの構造（Header.Payload.Signature）を解析し、期限切れチェックを実装してください。',
      initialCode: '// JWT の解析とバリデーション\nfunction decodeJWT(token) {\n  // ドットで分割し、Base64デコード\n}\n\nfunction isExpired(payload) {\n  // exp クレームで有効期限チェック\n}\n\n// テスト用JWT (Base64エンコード済み)\nconst header = btoa(JSON.stringify({ alg: "HS256", typ: "JWT" }));\nconst payload = btoa(JSON.stringify({\n  sub: "user123",\n  name: "Alice",\n  exp: Math.floor(Date.now() / 1000) + 3600\n}));\nconst fakeToken = `${header}.${payload}.fakesignature`;\n\nconst decoded = decodeJWT(fakeToken);\nconsole.log("Header:", decoded.header);\nconsole.log("Payload:", decoded.payload);\nconsole.log("Expired:", isExpired(decoded.payload));',
      solutionCode: 'function decodeJWT(token) {\n  const parts = token.split(".");\n  if (parts.length !== 3) throw new Error("Invalid JWT format");\n  return {\n    header: JSON.parse(atob(parts[0])),\n    payload: JSON.parse(atob(parts[1])),\n    signature: parts[2],\n  };\n}\n\nfunction isExpired(payload) {\n  if (!payload.exp) return false;\n  return Date.now() / 1000 > payload.exp;\n}\n\nconst header = btoa(JSON.stringify({ alg: "HS256", typ: "JWT" }));\nconst payload = btoa(JSON.stringify({\n  sub: "user123",\n  name: "Alice",\n  exp: Math.floor(Date.now() / 1000) + 3600\n}));\nconst fakeToken = `${header}.${payload}.fakesignature`;\n\nconst decoded = decodeJWT(fakeToken);\nconsole.log("Header:", decoded.header);\nconsole.log("Payload:", decoded.payload);\nconsole.log("Expired:", isExpired(decoded.payload));',
      expectedOutput: 'Header: { alg: "HS256", typ: "JWT" }\nPayload: { sub: "user123", name: "Alice", exp: ... }\nExpired: false',
      hints: ['JWTは header.payload.signature の3パート', 'atob() でBase64デコード'],
      explanation: 'JWT セキュリティの罠:\n1. alg: "none" を許可しない（署名検証をスキップ）\n2. 秘密鍵を十分に強固に（256bit以上）\n3. exp (有効期限) を必ず設定\n4. Access Token は短命(15分)、Refresh Token で更新\n5. JWTはステートレスなので即時無効化が困難 → ブラックリストまたは短命＋Refreshで対応\n6. 機密情報をペイロードに入れない（Base64なだけで暗号化されていない）',
