      description: 'レートリミットはブルートフォース攻撃やDDoSを緩和するため、一定時間内のリクエスト数を制限します。',
      task: 'Token Bucket アルゴリズムのレートリミッターを実装してください。',
      initialCode: 'class RateLimiter {\n  constructor(maxTokens, refillRate) {\n    // maxTokens: バケットの最大容量\n    // refillRate: 1秒あたりのトークン補充数\n  }\n\n  tryConsume(key) {\n    // リクエストを受け付けるか判定\n    // true: 許可, false: 拒否\n  }\n}\n\nconst limiter = new RateLimiter(5, 1);\nfor (let i = 0; i < 8; i++) {\n  const allowed = limiter.tryConsume("user1");\n  console.log(`Request ${i + 1}: ${allowed ? "OK" : "RATE LIMITED"}`);\n}',
      solutionCode: 'class RateLimiter {\n  constructor(maxTokens, refillRate) {\n    this.maxTokens = maxTokens;\n    this.refillRate = refillRate;\n    this.buckets = new Map();\n  }\n\n  tryConsume(key) {\n    const now = Date.now();\n    let bucket = this.buckets.get(key);\n    if (!bucket) {\n      bucket = { tokens: this.maxTokens, lastRefill: now };\n      this.buckets.set(key, bucket);\n    }\n    const elapsed = (now - bucket.lastRefill) / 1000;\n    bucket.tokens = Math.min(this.maxTokens, bucket.tokens + elapsed * this.refillRate);\n    bucket.lastRefill = now;\n    if (bucket.tokens >= 1) {\n      bucket.tokens -= 1;\n      return true;\n    }\n    return false;\n  }\n}\n\nconst limiter = new RateLimiter(5, 1);\nfor (let i = 0; i < 8; i++) {\n  const allowed = limiter.tryConsume("user1");\n  console.log(`Request ${i + 1}: ${allowed ? "OK" : "RATE LIMITED"}`);\n}',
