      initialCode: '// パストラバーサル防止\nconst path = require ? { resolve: (a, b) => a + "/" + b, normalize: (p) => p } : { resolve: (a, b) => a + "/" + b, normalize: (p) => p };\n\nfunction safePath(baseDir, userInput) {\n  // ベースディレクトリ外へのアクセスを防ぐ\n}\n\nconsole.log(safePath("/app/uploads", "photo.jpg"));\nconsole.log(safePath("/app/uploads", "../../../etc/passwd"));\nconsole.log(safePath("/app/uploads", "subdir/file.txt"));',
      solutionCode: 'function safePath(baseDir, userInput) {\n  const normalized = userInput\n    .replace(/\\.\\./g, "")\n    .replace(/\\/\\//g, "/")\n    .replace(/^[\\/]+/, "");\n  const fullPath = baseDir + "/" + normalized;\n\n  if (!fullPath.startsWith(baseDir + "/")) {\n    return { safe: false, path: null, error: "Path traversal detected" };\n  }\n  if (/\\0/.test(userInput)) {\n    return { safe: false, path: null, error: "Null byte injection detected" };\n  }\n  return { safe: true, path: fullPath, error: null };\n}\n\nconsole.log(safePath("/app/uploads", "photo.jpg"));\nconsole.log(safePath("/app/uploads", "../../../etc/passwd"));\nconsole.log(safePath("/app/uploads", "subdir/file.txt"));',
