      initialCode: '// 脆弱なコード:\n// exec("ping -c 1 " + userInput);\n// ユーザーが "google.com; rm -rf /" を入力すると...\n\nfunction sanitizeHostname(input) {\n  // ホスト名のバリデーション\n}\n\nconsole.log(sanitizeHostname("example.com"));\nconsole.log(sanitizeHostname("google.com; rm -rf /"));\nconsole.log(sanitizeHostname("8.8.8.8"));\nconsole.log(sanitizeHostname("$(cat /etc/passwd)"));',
      solutionCode: 'function sanitizeHostname(input) {\n  const hostnameRegex = /^[a-zA-Z0-9][a-zA-Z0-9.-]{0,253}[a-zA-Z0-9]$/;\n  const ipRegex = /^(\\d{1,3}\\.){3}\\d{1,3}$/;\n\n  if (hostnameRegex.test(input) || ipRegex.test(input)) {\n    if (ipRegex.test(input)) {\n      const parts = input.split(".").map(Number);\n      if (parts.some((p) => p > 255)) return { valid: false, reason: "Invalid IP" };\n    }\n    return { valid: true, sanitized: input };\n  }\n  return { valid: false, reason: "Invalid hostname" };\n}\n\nconsole.log(sanitizeHostname("example.com"));\nconsole.log(sanitizeHostname("google.com; rm -rf /"));\nconsole.log(sanitizeHostname("8.8.8.8"));\nconsole.log(sanitizeHostname("$(cat /etc/passwd)"));',
