      task: 'PKCEのcode_verifierとcode_challengeの生成を実装してください。',
      initialCode: '// PKCE (Proof Key for Code Exchange)\nfunction generateCodeVerifier() {\n  // 43-128文字のランダム文字列\n}\n\nfunction generateCodeChallenge(verifier) {\n  // SHA-256ハッシュのBase64URLエンコード（簡易版）\n}\n\nconst verifier = generateCodeVerifier();\nconst challenge = generateCodeChallenge(verifier);\n\nconsole.log("Verifier:", verifier);\nconsole.log("Challenge:", challenge);\nconsole.log("Verifier length:", verifier.length);',
      solutionCode: 'function generateCodeVerifier() {\n  const chars = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789-._~";\n  let verifier = "";\n  for (let i = 0; i < 64; i++) {\n    verifier += chars[Math.floor(Math.random() * chars.length)];\n  }\n  return verifier;\n}\n\nfunction generateCodeChallenge(verifier) {\n  let hash = 0;\n  for (let i = 0; i < verifier.length; i++) {\n    const ch = verifier.charCodeAt(i);\n    hash = ((hash << 5) - hash + ch) | 0;\n  }\n  return btoa(Math.abs(hash).toString(16))\n    .replace(/\\+/g, "-")\n    .replace(/\\//g, "_")\n    .replace(/=+$/, "");\n}\n\nconst verifier = generateCodeVerifier();\nconst challenge = generateCodeChallenge(verifier);\n\nconsole.log("Verifier:", verifier);\nconsole.log("Challenge:", challenge);\nconsole.log("Verifier length:", verifier.length);',
      expectedOutput: 'Verifier: ...(64文字ランダム)\nChallenge: ...(Base64URL)\nVerifier length: 64',
