      initialCode: '// XOR暗号（対称鍵暗号の概念）\nfunction xorEncrypt(text, key) {\n  // 各文字をキーとXOR\n}\n\nfunction xorDecrypt(encrypted, key) {\n  // XORは2回適用すると元に戻る\n}\n\nconst message = "Secret Message";\nconst key = "MySecretKey12345";\n\nconst encrypted = xorEncrypt(message, key);\nconst decrypted = xorDecrypt(encrypted, key);\n\nconsole.log("Original:", message);\nconsole.log("Encrypted:", encrypted);\nconsole.log("Decrypted:", decrypted);',
      solutionCode: 'function xorEncrypt(text, key) {\n  return text\n    .split("")\n    .map((ch, i) => {\n      const xored = ch.charCodeAt(0) ^ key.charCodeAt(i % key.length);\n      return xored.toString(16).padStart(2, "0");\n    })\n    .join("");\n}\n\nfunction xorDecrypt(hex, key) {\n  const bytes = hex.match(/.{2}/g) || [];\n  return bytes\n    .map((byte, i) => {\n      const xored = parseInt(byte, 16) ^ key.charCodeAt(i % key.length);\n      return String.fromCharCode(xored);\n    })\n    .join("");\n}\n\nconst message = "Secret Message";\nconst key = "MySecretKey12345";\n\nconst encrypted = xorEncrypt(message, key);\nconst decrypted = xorDecrypt(encrypted, key);\n\nconsole.log("Original:", message);\nconsole.log("Encrypted:", encrypted);\nconsole.log("Decrypted:", decrypted);',
      expectedOutput: 'Original: Secret Message\nEncrypted: ...(16進数文字列)\nDecrypted: Secret Message',
