      initialCode: '// フレームバスティング（iframe埋め込み防止）\nfunction preventClickjacking() {\n  // window.top との比較でiframe内かチェック\n}\n\n// CSPヘッダでのフレーム制御\nfunction getFrameHeaders() {\n  // X-Frame-Options と CSP frame-ancestors\n}\n\npreventClickjacking();\nconsole.log("Frame headers:", getFrameHeaders());',
      solutionCode: 'function preventClickjacking() {\n  try {\n    if (window.self !== window.top) {\n      console.log("WARNING: Running inside an iframe!");\n      console.log("In production: document.body.style.display = \'none\'");\n    } else {\n      console.log("OK: Not inside an iframe");\n    }\n  } catch (e) {\n    console.log("WARNING: Cross-origin iframe detected!");\n  }\n}\n\nfunction getFrameHeaders() {\n  return {\n    "X-Frame-Options": "DENY",\n    "Content-Security-Policy": "frame-ancestors \'none\'",\n  };\n}\n\npreventClickjacking();\nconsole.log("Frame headers:", getFrameHeaders());',
