      initialCode: '// プロトタイプ汚染のデモと防御\n\n// 脆弱なマージ関数\nfunction unsafeMerge(target, source) {\n  for (const key in source) {\n    if (typeof source[key] === "object") {\n      target[key] = target[key] || {};\n      unsafeMerge(target[key], source[key]);\n    } else {\n      target[key] = source[key];\n    }\n  }\n  return target;\n}\n\n// 安全なマージ関数を書く\nfunction safeMerge(target, source) {\n  // __proto__, constructor, prototype を拒否\n}\n\nconsole.log("Testing safe merge:");\nconst obj = {};\nsafeMerge(obj, JSON.parse(\'{"name": "ok", "__proto__": {"isAdmin": true}}\')); \nconsole.log("obj.name:", obj.name);\nconsole.log("obj.isAdmin:", obj.isAdmin);\nconsole.log("{}.isAdmin:", ({}).isAdmin);',
      solutionCode: 'function safeMerge(target, source) {\n  const BLOCKED_KEYS = new Set(["__proto__", "constructor", "prototype"]);\n\n  for (const key of Object.keys(source)) {\n    if (BLOCKED_KEYS.has(key)) {\n      console.log(`  [BLOCKED] Dangerous key: ${key}`);\n      continue;\n    }\n    if (\n      typeof source[key] === "object" &&\n      source[key] !== null &&\n      !Array.isArray(source[key])\n    ) {\n      target[key] = target[key] || {};\n      safeMerge(target[key], source[key]);\n    } else {\n      target[key] = source[key];\n    }\n  }\n  return target;\n}\n\nconsole.log("Testing safe merge:");\nconst obj = {};\nsafeMerge(obj, JSON.parse(\'{"name": "ok", "__proto__": {"isAdmin": true}}\'));\nconsole.log("obj.name:", obj.name);\nconsole.log("obj.isAdmin:", obj.isAdmin);\nconsole.log("{}.isAdmin:", ({}).isAdmin);',
      expectedOutput: 'Testing safe merge:\n  [BLOCKED] Dangerous key: __proto__\nobj.name: ok\nobj.isAdmin: undefined\n{}.isAdmin: undefined',
      hints: ['__proto__, constructor, prototype キーを拒否', 'Object.keys() は継承プロパティを含まない'],
      explanation: 'プロトタイプ汚染の防御:\n1. __proto__, constructor, prototype キーのブロック\n2. Object.create(null) で プロトタイプなしオブジェクト\n3. Object.freeze(Object.prototype) で凍結\n4. Map を使う（プロトタイプチェーンなし）\n5. ライブラリの使用: lodash.merge は修正済み、しかし古いバージョンは脆弱\n\nNode.js の --disable-proto=throw フラグも有効です。',
